ha-card {
  border-radius: 20px;
  background: linear-gradient(145deg, rgba(49,196,141,.26), rgba(8,32,24,.92));
  border: 1px solid rgba(74,222,128,.34);
  box-shadow: 0 16px 40px rgba(0,0,0,.34), inset 0 1px 0 rgba(255,255,255,.08);
  overflow: hidden;
}
ha-card:hover {
  transform: translateY(-1px);
  box-shadow: 0 20px 48px rgba(0,0,0,.42), inset 0 1px 0 rgba(255,255,255,.10);
}

